hooks.command:
cat | python3 -c "
import sys, json, subprocess
data = json.load(sys.stdin)
f = data.get('tool_input', {}).get('file_path', '')
if not f: sys.exit(0)
if f.endswith('.py'):
    r = subprocess.run(['python3', '-m', 'py_compile', f], capture_output=True, text=True)
    if r.returncode != 0:
        print(r.stderr, file=sys.stderr)
if f.endswith('.json'):
    r = subprocess.run(['python3', '-m', 'json.tool', f], capture_output=True, text=True)
    if r.returncode != 0:
        print(f'Invalid JSON: {f}', file=sys.stderr)
"
